1682 /// Matches instructions with Opcode and three operands.
1683 template <typename T0, unsigned Opcode> struct OneOps_match {
1684   T0 Op1;
1685 
1686   OneOps_match(const T0 &Op1) : Op1(Op1) {}
1687 
1688   template <typename OpTy> bool match(OpTy *V) {
1689     if (V->getValueID() == Value::InstructionVal + Opcode) {
1690       auto *I = cast<Instruction>(V);
1691       return Op1.match(I->getOperand(0));
1692     }
1693     return false;
1694   }
1695 };
