1738 /// Try to convert "shuffle (castop), (castop)" with a shared castop operand
1739 /// into "castop (shuffle)".
1740 bool VectorCombine::foldShuffleOfCastops(Instruction &I) {
1741   Value *V0, *V1;
1742   ArrayRef<int> OldMask;
1743   if (!match(&I, m_Shuffle(m_Value(V0), m_Value(V1), m_Mask(OldMask))))
1744     return false;
1745 
1746   auto *C0 = dyn_cast<CastInst>(V0);
1747   auto *C1 = dyn_cast<CastInst>(V1);
1748   if (!C0 || !C1)
1749     return false;
1750 
1751   Instruction::CastOps Opcode = C0->getOpcode();
1752   if (C0->getSrcTy() != C1->getSrcTy())
1753     return false;
1754 
1755   // Handle shuffle(zext_nneg(x), sext(y)) -> sext(shuffle(x,y)) folds.
1756   if (Opcode != C1->getOpcode()) {
1757     if (match(C0, m_SExtLike(m_Value())) && match(C1, m_SExtLike(m_Value())))
1758       Opcode = Instruction::SExt;
1759     else
1760       return false;
1761   }
1762 
1763   auto *ShuffleDstTy = dyn_cast<FixedVectorType>(I.getType());
1764   auto *CastDstTy = dyn_cast<FixedVectorType>(C0->getDestTy());
1765   auto *CastSrcTy = dyn_cast<FixedVectorType>(C0->getSrcTy());
1766   if (!ShuffleDstTy || !CastDstTy || !CastSrcTy)
1767     return false;
1768 
1769   unsigned NumSrcElts = CastSrcTy->getNumElements();
1770   unsigned NumDstElts = CastDstTy->getNumElements();
1771   assert((NumDstElts == NumSrcElts || Opcode == Instruction::BitCast) &&
1772          "Only bitcasts expected to alter src/dst element counts");
