1775   // e.g. <32 x i40> -> <40 x i32>
1776   if (NumDstElts != NumSrcElts && (NumSrcElts % NumDstElts) != 0 &&
1777       (NumDstElts % NumSrcElts) != 0)
1778     return false;
1779 
1780   SmallVector<int, 16> NewMask;
1781   if (NumSrcElts >= NumDstElts) {
1782     // The bitcast is from wide to narrow/equal elements. The shuffle mask can
1783     // always be expanded to the equivalent form choosing narrower elements.
1784     assert(NumSrcElts % NumDstElts == 0 && "Unexpected shuffle mask");
