1789     // must choose consecutive elements to allow casting first.
1790     assert(NumDstElts % NumSrcElts == 0 && "Unexpected shuffle mask");
1791     unsigned ScaleFactor = NumDstElts / NumSrcElts;
1792     if (!widenShuffleMaskElts(ScaleFactor, OldMask, NewMask))
